#include<bits/stdc++.h>
using namespace std;
struct node{
    int x,y;
}a[105];
int n,k,old;
int dp[105][105];
bool cmp(node x,node y){
    return x.x<y.x;
}
int main(){
    cin>>n>>k;
    for(int i=1;i<=n;i++) cin>>a[i].x>>a[i].y;
    sort(a+1,a+1+n,cmp);
    for(int i=0;i<=k;i++){
        for(int j=1;j<=n;j++){
            if(j==1&&i==0){
                dp[i][j]=0;
            }else if(j==1){
                dp[i][j]=dp[i-1][j];
                old=1;
            }else if(i==0){
                dp[i][j]=dp[i][j-1]+abs(a[j-1].y-a[j].y);
            }else{
                if(dp[i-1][j-1]<dp[i][j-1]+abs(a[old].y-a[j].y)){
                    dp[i][j]=dp[i-1][j-1];
                    old=j-1;
                }else{

                    dp[i][j]=dp[i][j-1]+abs(a[old].y-a[j].y);
                    old=j;
                }

            }
        }
    }
    cout<<dp[k][n];
}
